/**
 * Bubble Sort — Trace questions & Solve problems
 *
 * Default array: [64, 34, 25, 12, 22, 11, 90]
 * Steps generated by generateBubbleSortSteps walk through passes and swaps.
 */

import type { TraceQuestion, SolveProblem } from "./binarySearchChallenges"

// Steps overview for [64, 34, 25, 12, 22, 11, 90]:
//   0: init
//   1: compare arr[0]=64 vs arr[1]=34
//   2: swap 64 and 34 → [34, 64, 25, ...]
//   3: compare arr[1]=64 vs arr[2]=25
//   4: swap 64 and 25 → [34, 25, 64, ...]
//   ... continues through passes

